Estado: Activo

parameters.jsCode:
//////////////////////////////
// Extraemos los datos de la fila actual
const f = ($json.fecha_creacion) ? $json.fecha_creacion.toString().substring(0, 10) : "S/F";
const id = $json.id_ticket || "N/A";
const tipo = $json.tipo || "Genérico";
const prio = $json.prioridad || "Normal";
const desc = $json.descripcion || "Sin detalle";
const est = $json.estado || "Abierto";

// Creamos el bloque visual para ESTE ticket
const bloque = `📅 <b>${f}</b> | 🆔 <code>${id}</code>\n` +
               `🔹 <b>Tipo:</b> ${tipo} | ⚡ <b>Prio:</b> ${prio}\n` +
               `📝 <b>Desc:</b> ${desc}\n` +
               `📌 <b>Estado:</b> ${est === 'Cerrado' ? '🔴' : '🟢'} ${est}\n` +
               `----------------------------------\n`;

// Devolvemos el bloque listo
return { bloque_texto: bloque };

parameters.text:
=🔍 Consultando tus solicitudes...

He encontrado las siguientes solicitudes registradas bajo tu usuario. Aquí tienes el resumen de su estado actual:

{{ $json.bloque_texto }}

parameters.jsCode:
///////////////
// Extraemos los datos de la fila de registros
// Formateamos la fecha para que no ocupe tanto espacio
const fecha = ($json.marca_temporal) ? $json.marca_temporal.toString().replace('T', ' ').substring(0, 16) : "S/F";
const pantalla = $json.pantalla || "inicio";
const opcion = $json.opcion || "ninguna";
const resultado = $json.resultado || "visto";

// Creamos el bloque visual para cada movimiento del usuario
const bloque = `🕒 <b>${fecha}</b>\n` +
               `🖥️ <b>Sección:</b> <code>${pantalla}</code>\n` +
               `🔘 <b>Acción:</b> ${opcion}\n` +
               `✅ <b>Resultado:</b> <i>${resultado}</i>\n` +
               `----------------------------------\n`;

return { bloque_reporte: bloque };

